import { stdout } from "process";
import { AgentConfig } from "./agent-config.js";
import {
  pruneContext,
  truncateForContext,
  truncateForDisplay,
} from "./context-management.js";
import { logger } from "./logger.js";
import { Message, ToolMessage } from "./message.js";
import { LLMProvider, LLMResponse } from "./providers/llm-provider.js";

type RunnerConstructorProps = {
  llmProvider: LLMProvider;
  agentConfig: AgentConfig;
  maxSteps?: number;
  maxContextTokens?: number;
};

type RunnerEvent =
  | { type: "text"; text: string }
  | { type: "text_stream"; text: string }
  | { type: "text_stream_end" }
  | { type: "state"; message: Message }
  | { type: "tool_use"; name: string; input: unknown }
  | {
      type: "tool_result";
      output: string;
      /** Output completo (sin truncar) para poder mostrar un resumen real. */
      rawOutput?: string;
    };

class Runner {
  // Métricas de una sola corrida (se resetean con resetMetrics()).
  // El acumulado histórico lo mantiene Session (addUsage), que es el
  // único dueño persistente del costo total.
  #llmProvider: LLMProvider;
  #agentConfig: AgentConfig;
  #maxSteps: number;
  #maxContextTokens: number;
  #metrics: {
    totalInputTokens: number;
    totalOutputTokens: number;
    totalToolCalls: number;
    totalCost: number;
    startTime: number;
  };

  constructor({
    llmProvider,
    agentConfig,
    maxSteps = 15,
    maxContextTokens = 100_000,
  }: RunnerConstructorProps) {
    this.#llmProvider = llmProvider;
    this.#agentConfig = agentConfig;
    this.#maxSteps = maxSteps;
    this.#maxContextTokens = maxContextTokens;
    this.#metrics = {
      totalInputTokens: 0,
      totalOutputTokens: 0,
      totalToolCalls: 0,
      totalCost: 0,
      startTime: Date.now(),
    };
  }

  async *run(incomingContext: readonly Message[]): AsyncGenerator<RunnerEvent> {
    const workingContext = [...incomingContext];
    logger.info(`Starting runner with max steps: ${this.#maxSteps}`);

    let steps = this.#maxSteps;
    while (steps > 0) {
      const prunedContext = pruneContext(
        workingContext,
        this.#maxContextTokens,
      );

      // Usamos streaming si el provider lo soporta
      const hasStream = typeof this.#llmProvider.callStream === "function";
      const toolBlocks: Array<{ id: string; name: string; input: unknown }> =
        [];
      const textParts: string[] = [];
      let stopReason: "end_turn" | "tool_use" | "max_tokens" = "end_turn";

      if (hasStream) {
        stdout.write("tiene stream");
        const stream = this.#llmProvider.callStream(
          prunedContext,
          this.#agentConfig,
        );

        for await (const event of stream) {
          if (event.type === "text") {
            textParts.push(event.text);
            yield { type: "text_stream", text: event.text };
          } else if (event.type === "tool_use") {
            toolBlocks.push({
              id: event.id,
              name: event.name,
              input: event.input,
            });
          } else if (event.type === "done") {
            stdout.write("event done stream");
            stopReason = event.stop_reason;
            this.#metrics.totalInputTokens += event.usage.input_tokens;
            this.#metrics.totalOutputTokens += event.usage.output_tokens;
            this.#metrics.totalCost += event.cost;
          }
        }

        if (textParts.length > 0) {
          stdout.write("stream_end");
          yield { type: "text_stream_end" };
        }
      } else {
        const data: LLMResponse = await this.#llmProvider.call(
          prunedContext,
          this.#agentConfig,
        );

        this.#metrics.totalInputTokens += data.usage.input_tokens;
        this.#metrics.totalOutputTokens += data.usage.output_tokens;
        this.#metrics.totalCost += data.cost;

        for (const block of data.content) {
          if (block.type === "text") {
            textParts.push(block.text);
            yield { type: "text", text: block.text };
          }
          if (block.type === "tool_use") {
            toolBlocks.push({
              id: block.id,
              name: block.name,
              input: block.input,
            });
          }
        }

        stopReason = data.stop_reason;
      }

      // Construir el mensaje assistant completo
      const assistantContent: Message["content"] = [];
      if (textParts.length > 0) {
        assistantContent.push({ type: "text", text: textParts.join("") });
      }
      for (const tb of toolBlocks) {
        assistantContent.push({
          type: "tool_use",
          id: tb.id,
          name: tb.name,
          input: tb.input,
        });
      }

      // Si el LLM no produjo ni texto ni tool calls (ej: solo bloques
      // thinking filtrados), ponemos un fallback para que la sesión no
      // guarde un mensaje vacío.
      const assistantMessage: Message = {
        role: "assistant",
        content:
          assistantContent.length > 0
            ? assistantContent
            : [
                {
                  type: "text",
                  text: "(El modelo no produjo contenido visible en este turno)",
                },
              ],
      };
      workingContext.push(assistantMessage);
      yield { type: "state", message: assistantMessage };

      // Ejecutar tools
      const toolResults: ToolMessage[] = [];
      for (const block of toolBlocks) {
        this.#metrics.totalToolCalls++;

        const tool = this.#agentConfig.getTool(block.name);
        if (!tool) {
          const output = `Error: unknown tool "${block.name}"`;
          logger.error(output);
          yield { type: "tool_result", output };
          toolResults.push({
            type: "tool_result",
            tool_use_id: block.id,
            content: output,
            is_error: true,
          });
          continue;
        }

        yield { type: "tool_use", name: tool.name, input: block.input };

        let output: string;
        let isError = false;
        try {
          output = tool.execute(block.input) as string;
        } catch (err: unknown) {
          isError = true;
          output = `Error executing tool "${tool.name}": ${err instanceof Error ? err.message : String(err)}`;
          logger.error("Tool execution threw", {
            tool: tool.name,
            error: output,
          });
        }

        // Display: límite visual. Modelo: safety net por tokens.
        const shown = truncateForDisplay(output);
        const forModel = truncateForContext(output, this.#maxContextTokens);

        yield { type: "tool_result", output: shown, rawOutput: output };
        toolResults.push({
          type: "tool_result",
          tool_use_id: block.id,
          content: forModel,
          is_error: isError,
        });
      }

      if (toolResults.length > 0) {
        const toolMessage: Message = { role: "user", content: toolResults };
        workingContext.push(toolMessage);
        yield { type: "state", message: toolMessage };
      }

      if (stopReason === "max_tokens") {
        logger.warn("Respuesta cortada por max_tokens");
        yield {
          type: "text",
          text: "⚠ La respuesta se cortó (max_tokens). Subí el límite o pedí algo más chico.",
        };
        break;
      }

      if (stopReason === "end_turn") {
        logger.info("Agent finished (end_turn)");
        break;
      }
      steps--;
      if (steps === 0) {
        logger.warn(`Max steps reached (${this.#maxSteps})`);
      }
    }
  }

  getMetrics() {
    return {
      ...this.#metrics,
      durationMs: Date.now() - this.#metrics.startTime,
    };
  }

  resetMetrics() {
    this.#metrics = {
      totalInputTokens: 0,
      totalOutputTokens: 0,
      totalToolCalls: 0,
      totalCost: 0,
      startTime: Date.now(),
    };
  }
}

export { Runner, RunnerEvent };

#!/usr/bin/env node
import { existsSync, readFileSync } from "fs";
import { homedir } from "os";
import { join } from "path";
import { stdout } from "process";
import dotenv from "dotenv";
import { AgentConfig } from "./agent-config.js";
import { Context } from "./app-context.js";
import { dispatchCommand, modalCommandsMap } from "./commands/index.js";
import { validateEnv } from "./config.js";
import { logger } from "./logger.js";
import { OpenRouterProvider } from "./providers/openrouter-llm-provider.js";
import { Runner, RunnerEvent } from "./runner.js";
import { Message } from "./message.js";
import { Session } from "./session.js";
import { BashTool } from "./tools/bash.js";
import { EditTool } from "./tools/edit.js";
import { GrepTool } from "./tools/grep.js";
import { ReadTool } from "./tools/read.js";
import { WriteTool } from "./tools/write.js";
import {
  DisplayAssistantText,
  DisplayToolCall,
  DisplayToolResult,
} from "./tui/components/display-text.js";
import { LineEditor } from "./tui/components/line-editor.js";
import { Prompt } from "./tui/components/prompt.js";
import { Spinner } from "./tui/components/spinner.js";
import { Screen } from "./tui/screen.js";
import { disableRawMode, enableRawMode } from "./tui/terminal.js";
import { dim } from "./tui/theme.js";
import { expandFileMentions } from "./file-mentions.js";

// Carga la .env del cwd (overrides por proyecto) y, como fallback, la global
// ~/.omega/.env. dotenv NO pisa vars ya seteadas, así que el cwd gana y la
// global completa el resto (tu API key) → `omega` anda desde cualquier carpeta.
dotenv.config();
dotenv.config({ path: join(homedir(), ".omega", ".env") });

const SYSTEM_PROMPT = `Sos omega, un asistente de coding que trabaja en el proyecto del usuario.
Tenés tools para leer, escribir, editar y ejecutar comandos.

Tools:
- read: leé un archivo antes de editarlo.
- bash: explorá el proyecto (ls, grep, find) y ejecutá comandos.
- edit: para cambios quirúrgicos; el texto a reemplazar debe matchear exacto.
- write: solo para archivos nuevos o reescrituras completas.

Cómo trabajás:
- Explorá lo necesario antes de cambiar nada: leé los archivos relevantes
  para entender el contexto.
- Después de editar código, verificá que no rompiste nada (typecheck, tests
  o lint según el proyecto) y corregí si hace falta.
- Actuá solo en lo rutinario, pero pará y pedí confirmación antes de instalar
  dependencias, borrar archivos, o cualquier comando destructivo o irreversible.

Estilo:
- Respondé siempre en español.
- Sé conciso: explicá brevemente qué hiciste y por qué, sin resúmenes largos.
- Texto plano. Sin emojis ni formato decorativo.`;

function loadProjectContext(): string {
  const path = "AGENT.md";
  if (!existsSync(path)) return "";
  const content = readFileSync(path, "utf-8").trim();
  if (!content) return "";
  return `\n\n## Contexto del proyecto (${path})\n\n${content}`;
}

const main = async () => {
  enableRawMode();
  const config = validateEnv();
  const session = new Session({
    dir: ".omega/sessions",
    maxContextTokens: config.maxContextTokens,
  });
  logger.setLogFile(`.omega/logs/${session.id}.log`);
  logger.info("Omega agent starting", { session: session.id });

  const fullSystemPrompt = SYSTEM_PROMPT + loadProjectContext();

  const haikuAgent = new AgentConfig({
    systemPrompt: fullSystemPrompt,
    model: config.model,
    maxTokens: config.maxTokens,
  });

  haikuAgent
    .addTool(new BashTool())
    .addTool(new GrepTool())
    .addTool(new ReadTool())
    .addTool(new EditTool())
    .addTool(new WriteTool());

  const llmprovider = new OpenRouterProvider(config.openrouterApiKey);

  const runner = new Runner({
    llmProvider: llmprovider,
    agentConfig: haikuAgent,
    maxSteps: config.maxSteps,
    maxContextTokens: config.maxContextTokens,
  });

  const screen = new Screen(config.screenPadding);
  const spinner = new Spinner(screen);
  const assistantText = new DisplayAssistantText(screen);
  const toolCallText = new DisplayToolCall(screen);
  const toolResultText = new DisplayToolResult(screen);

  const ctx = new Context({
    session,
    agentConfig: haikuAgent,
    runner,
    screen,
  });

  const lineEditor = new LineEditor();

  while (true) {
    const prompt = new Prompt({
      editor: lineEditor,
      ctx,
      modals: modalCommandsMap,
    });
    const result = await screen.readLine(prompt);

    // Historial: lo tipeado (incluye comandos).
    const typed = lineEditor.getResult();
    if (typed.trim() !== "") {
      lineEditor.addToHistory(typed);
    }

    // Un comando modal (ej: /resume) ya hizo su efecto dentro del Prompt.
    // No ecoamos "> /resume"; solo mostramos la confirmación (si hay) y
    // limpiamos el editor. printAbove("") limpia la lista sin imprimir nada.
    if (result.kind === "modal") {
      lineEditor.reset();
      screen.printAbove(result.message ?? "");
      continue;
    }

    const input = result.text;

    // Eco del input: usamos printAbove para que se inserte en el scrollback
    // sin pisar la región viva (el Screen limpia y redibuja automáticamente).
    const echo = lineEditor.renderEcho();
    lineEditor.reset();
    screen.printAbove(`\n${echo}`);

    if (await dispatchCommand(input, ctx)) {
      continue;
    }

    if (input === "exit") {
      logger.info("Omega agent stopped");
      // El listener de stdin del Screen mantiene vivo el event loop, así que
      // un break dejaría el proceso colgado. Salimos explícito; el handler de
      // process.on("exit") restaura la raw mode.
      disableRawMode();
      process.exit(0);
    }

    const session = ctx.session;

    const resolvedInput = expandFileMentions(input);
    const userContent: Message["content"] = [];
    if (resolvedInput.text) {
      userContent.push({ type: "text", text: resolvedInput.text });
    }
    for (const img of resolvedInput.images) {
      userContent.push(img);
    }

    // Si solo hay texto, lo pasamos como string simple para mantener
    // compatibilidad con el formato legacy
    const firstItem = userContent[0];
    if (
      userContent.length === 1 &&
      typeof firstItem === "object" &&
      "type" in firstItem &&
      firstItem.type === "text"
    ) {
      session.addUserMessage((firstItem as { type: "text"; text: string }).text);
    } else {
      session.addUserMessage(userContent);
    }

    let iterator: AsyncGenerator<unknown>;
    try {
      iterator = runner.run(session.messages);

      spinner.start();
      let item = await iterator.next();

      while (!item.done) {
        const { value } = item as { value: RunnerEvent };

        if (value.type === "text_stream") {
          // Apenas empieza a salir texto, frenamos el spinner: ya estás viendo
          // la respuesta, "Pensando" sobra (y si no, queda colgado en la cola
          // del stream esperando el chunk final de usage). stop() es idempotente.
          spinner.stop();
          assistantText.displayStream(value.text);
        }

        if (value.type === "text_stream_end") {
          assistantText.endStream();
        }

        if (value.type === "text") {
          spinner.stop();
          assistantText.display(value.text);
        }

        if (value.type === "tool_use") {
          spinner.stop();
          toolCallText.call(value.name, value.input, ctx.verbose);
        }

        if (value.type === "tool_result") {
          toolResultText.result(value.output, ctx.verbose, value.rawOutput);
          spinner.start();
        }

        if (value.type === "state") {
          session.addMessage(value.message);
        }

        item = await iterator.next();
      }
      spinner.stop();
      // Redundante: screen.redrawLive() garantiza que la línea de estado
      // del spinner se limpie aunque algún timer encolado haya pintado
      // justo antes del stop.
      screen.redrawLive();
    } catch (err: unknown) {
      // Nos aseguramos de que el spinner se detenga ante cualquier error
      spinner.stop();
      screen.redrawLive();
      const msg = err instanceof Error ? err.message : String(err);
      logger.error("Runner error", msg);
      screen.printAbove(dim(`Error: ${msg}`));
    }

    // Métricas de la iteración
    const metrics = runner.getMetrics();
    session.addUsage(
      metrics.totalInputTokens,
      metrics.totalOutputTokens,
      metrics.totalCost,
    );
    const durationSec = (metrics.durationMs / 1000).toFixed(1);
    const costStr =
      metrics.totalCost < 0.01 ? "<$0.01" : `${metrics.totalCost.toFixed(2)}`;
    const runningStr =
      session.totalCost < 0.01 ? "<$0.01" : `${session.totalCost.toFixed(2)}`;
    const metricsLine = `~ ctx: ${session.contextTokens} tk · ${metrics.totalToolCalls} tools · in: ${metrics.totalInputTokens} · out: ${metrics.totalOutputTokens} tokens · ${durationSec}s · ${costStr} (total: ${runningStr})`;
    screen.printAbove(dim(`\n${metricsLine}`));
    runner.resetMetrics();
  }
};

main().catch((err) => {
  disableRawMode();
  console.log(err);
  logger.error("Fatal error", err);
  process.exit(1);
});

import { Tool } from "./tools/tool.js";

type AgentConfigConstructorProps = {
  systemPrompt: string;
  model: string;
  maxTokens: number;
};

class AgentConfig {
  #systemPrompt: string;
  #model: string;
  #max_tokens: number;
  #tools: Record<string, Tool<unknown, unknown>>;

  constructor({ model, maxTokens, systemPrompt }: AgentConfigConstructorProps) {
    this.#systemPrompt = systemPrompt;
    this.#model = model;
    this.#max_tokens = maxTokens;
    this.#tools = {};
  }

  addTool(tool: Tool<unknown, unknown>): AgentConfig {
    this.#tools = { ...this.#tools, [tool.name]: tool };
    return this;
  }

  getTool(name: string) {
    return this.#tools[name];
  }

  get systemPrompt() {
    return this.#systemPrompt;
  }

  get model() {
    return this.#model;
  }

  get maxTokens() {
    return this.#max_tokens;
  }

  tools() {
    return this.#tools;
  }

  toJSON() {
    return {
      model: this.#model,
      max_tokens: this.#max_tokens,
      tools: Object.values(this.#tools).map((t) => t.toJSON()),
    };
  }
}

export { AgentConfig };

type ToolConstructorProps = {
  name: string;
  description: string;
  schema: Record<string, unknown>;
};

export abstract class Tool<Tin, Tout> {
  #name: string;
  #description: string;
  #schema: Record<string, unknown>;

  constructor({ name, description, schema }: ToolConstructorProps) {
    this.#name = name;
    this.#description = description;
    this.#schema = schema;
  }

  abstract execute(input: Tin): Tout;

  get name() {
    return this.#name;
  }

  toJSON() {
    return {
      name: this.#name,
      description: this.#description,
      input_schema: this.#schema,
    };
  }
}

import { AgentConfig } from "../agent-config.js";
import { logger } from "../logger.js";
import { Message, ToolMessage, ImageMessage } from "../message.js";
import { Block, calculateCost, LLMProvider, LLMResponse, StreamEvent, TextBlock, ToolUseBlock } from "./llm-provider.js";

const TIMEOUT_MS = 60000;
const MAX_RETRIES = 3;
const INITIAL_BACKOFF_MS = 1000;

// ── Tipos internos OpenAI/OpenRouter ─────────────────────────────────────────

type OpenAIToolCall = {
  id: string;
  type: "function";
  function: { name: string; arguments: string };
};

type OpenAIMessage =
  | { role: "system"; content: string }
  | {
      role: "user";
      content:
        | string
        | Array<
            | { type: "text"; text: string }
            | { type: "image_url"; image_url: { url: string } }
          >;
    }
  | {
      role: "assistant";
      content: string | null;
      tool_calls?: OpenAIToolCall[];
    }
  | { role: "tool"; tool_call_id: string; content: string };

type OpenAITool = {
  type: "function";
  function: { name: string; description: string; parameters: unknown };
};

// ── Helpers de traducción ─────────────────────────────────────────────────────

export function translateMessages(messages: Message[], systemPrompt: string): OpenAIMessage[] {
  const result: OpenAIMessage[] = [{ role: "system", content: systemPrompt }];

  for (const msg of messages) {
    if (msg.role === "user") {
      // content string simple
      if (typeof msg.content === "string") {
        result.push({ role: "user", content: msg.content });
        continue;
      }

      // content array: puede ser tool_results o texto
      if (Array.isArray(msg.content)) {
        const items = msg.content;

        // Si el primer elemento es tool_result, explotamos en mensajes "tool" separados
        if (items.length > 0 && (items[0] as ToolMessage).type === "tool_result") {
          for (const item of items) {
            const tr = item as ToolMessage;
            result.push({
              role: "tool",
              tool_call_id: tr.tool_use_id,
              content: typeof tr.content === "string" ? tr.content : JSON.stringify(tr.content),
            });
          }
        } else {
          // Array de TextMessage e ImageMessage — puede ser texto simple o multimodal
          const hasImages = items.some((b) => typeof b === "object" && (b as { type: string }).type === "image");
          if (hasImages) {
            // Formato multimodal: array de content parts
            const contentParts: Array<{ type: "text"; text: string } | { type: "image_url"; image_url: { url: string } }> = [];
            for (const item of items) {
              if (typeof item === "string") {
                contentParts.push({ type: "text", text: item });
              } else if ((item as { type: string }).type === "text") {
                contentParts.push({ type: "text", text: (item as { text: string }).text });
              } else if ((item as { type: string }).type === "image") {
                const img = item as ImageMessage;
                contentParts.push({
                  type: "image_url",
                  image_url: {
                    url: `data:${img.source.media_type};base64,${img.source.data}`,
                  },
                });
              }
            }
            result.push({ role: "user", content: contentParts });
          } else {
            // array de TextMessage — concatenar
            const text = items
              .map((b) => (typeof b === "string" ? b : (b as { text: string }).text ?? ""))
              .join("");
            result.push({ role: "user", content: text });
          }
        }
        continue;
      }

      // TextMessage objeto suelto
      const textContent =
        typeof msg.content === "object" && "text" in (msg.content as object)
          ? (msg.content as { text: string }).text
          : String(msg.content);
      result.push({ role: "user", content: textContent });
    } else if (msg.role === "assistant") {
      if (Array.isArray(msg.content)) {
        const textParts: string[] = [];
        const toolCalls: OpenAIToolCall[] = [];

        for (const block of msg.content) {
          if (typeof block === "string") {
            textParts.push(block);
          } else if ((block as { type: string }).type === "text") {
            textParts.push((block as TextBlock).text);
          } else if ((block as { type: string }).type === "tool_use") {
            const tb = block as unknown as ToolUseBlock;
            toolCalls.push({
              id: tb.id,
              type: "function",
              function: { name: tb.name, arguments: JSON.stringify(tb.input) },
            });
          }
        }

        const assistantMsg: OpenAIMessage = {
          role: "assistant",
          content: textParts.length > 0 ? textParts.join("") : null,
        };
        if (toolCalls.length > 0) {
          (assistantMsg as { role: "assistant"; content: string | null; tool_calls?: OpenAIToolCall[] }).tool_calls = toolCalls;
        }
        result.push(assistantMsg);
      } else {
        // string simple
        const text = typeof msg.content === "string" ? msg.content : String(msg.content);
        result.push({ role: "assistant", content: text });
      }
    }
  }

  return result;
}

export function translateTools(agent: AgentConfig): OpenAITool[] {
  return Object.values(agent.tools()).map((t) => {
    const json = t.toJSON();
    return {
      type: "function",
      function: {
        name: json.name,
        description: json.description,
        parameters: json.input_schema,
      },
    };
  });
}

export function parseResponse(
  data: Record<string, unknown>,
  model: string,
  openrouterCostHeader: string | null,
): LLMResponse {
  const choice = (data.choices as Record<string, unknown>[])[0];
  const msg = choice.message as Record<string, unknown>;
  const content: Block[] = [];

  // content puede ser string o array de bloques
  if (typeof msg.content === "string" && msg.content.length > 0) {
    content.push({ type: "text", text: msg.content });
  } else if (Array.isArray(msg.content)) {
    for (const block of msg.content as Array<Record<string, unknown>>) {
      if (block.type === "text" && typeof block.text === "string") {
        content.push({ type: "text", text: block.text });
      }
      if (block.type === "tool_use") {
        content.push({
          type: "tool_use",
          id: block.id as string,
          name: block.name as string,
          input: block.input,
        });
      }
      // Ignorar bloques thinking, redacted_thinking, etc.
    }
  }

  const toolCalls = msg.tool_calls as OpenAIToolCall[] | undefined;
  if (Array.isArray(toolCalls)) {
    for (const tc of toolCalls) {
      let input: unknown;
      try {
        // Si arguments ya es un objeto (puede pasar según el provider), usarlo directo
        input = typeof tc.function.arguments === "string"
          ? JSON.parse(tc.function.arguments)
          : tc.function.arguments;
      } catch {
        logger.warn("Malformed tool call arguments from LLM, using empty object", {
          tool: tc.function.name,
          arguments: tc.function.arguments,
        });
        input = {};
      }
      content.push({
        type: "tool_use",
        id: tc.id,
        name: tc.function.name,
        input,
      });
    }
  }

  const finishReason = choice.finish_reason as string;
  const stop_reason: LLMResponse["stop_reason"] =
    finishReason === "tool_calls" ? "tool_use" : finishReason === "max_tokens" ? "max_tokens" : "end_turn";

  const usageData = data.usage as Record<string, number>;

  // OpenRouter devuelve el costo real en headers; si está disponible lo usamos,
  // si no, estimamos con nuestra tabla de precios.
  let cost: number;
  if (openrouterCostHeader !== null) {
    cost = parseFloat(openrouterCostHeader);
  } else {
    cost = calculateCost(model, usageData.prompt_tokens, usageData.completion_tokens);
  }

  return {
    content,
    stop_reason,
    usage: {
      input_tokens: usageData.prompt_tokens,
      output_tokens: usageData.completion_tokens,
    },
    cost,
  };
}

// ── Provider ──────────────────────────────────────────────────────────────────

class OpenRouterProvider extends LLMProvider {
  constructor(apiKey: string) {
    super({
      apiKey,
      url: "https://openrouter.ai/api/v1/chat/completions",
    });
  }

  private async sleep(ms: number): Promise<void> {
    return new Promise((resolve) => setTimeout(resolve, ms));
  }

  private async callWithRetry(
    messages: Message[],
    agent: AgentConfig,
    attempt: number = 1,
  ): Promise<LLMResponse> {
    const headers: Record<string, string> = {
      Authorization: `Bearer ${this.apiKey()}`,
      "Content-Type": "application/json",
    };

    const body = {
      model: agent.model,
      messages: translateMessages(messages, agent.systemPrompt),
      tools: translateTools(agent),
      max_tokens: agent.maxTokens,
    };

    try {
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), TIMEOUT_MS);

      const response = await fetch(this.url(), {
        method: "POST",
        headers,
        body: JSON.stringify(body),
        signal: controller.signal,
      });

      clearTimeout(timeoutId);

      if (response.ok) {
        const data = await response.json();
        const costHeader = response.headers.get("x-openrouter-cost");
        logger.info("OpenRouter API call successful", { cost: costHeader });
        return parseResponse(data, agent.model, costHeader);
      }

      if (response.status === 401) {
        const error = "OpenRouter: Invalid API key";
        logger.error(error);
        throw new Error(error);
      }

      if (response.status === 429 || response.status === 529) {
        if (attempt < MAX_RETRIES) {
          const backoffMs = INITIAL_BACKOFF_MS * Math.pow(2, attempt - 1);
          logger.warn(
            `OpenRouter rate limited. Retrying in ${backoffMs}ms (attempt ${attempt}/${MAX_RETRIES})`,
          );
          await this.sleep(backoffMs);
          return this.callWithRetry(messages, agent, attempt + 1);
        }
      }

      const errorData = await response.json();
      logger.error(`OpenRouter API error (${response.status})`, errorData);
      throw new Error(
        `OpenRouter API error: ${response.status} - ${JSON.stringify(errorData)}`,
      );
    } catch (err: unknown) {
      if (err instanceof Error && err.name === "AbortError") {
        logger.error("OpenRouter request timeout");
        throw new Error(`Request timeout after ${TIMEOUT_MS}ms`);
      }
      throw err;
    }
  }

  async call(messages: Message[], agent: AgentConfig): Promise<LLMResponse> {
    logger.info("Making API call to OpenRouter");
    return this.callWithRetry(messages, agent);
  }

  async *callStream(
    messages: Message[],
    agent: AgentConfig,
  ): AsyncGenerator<StreamEvent> {
    const headers: Record<string, string> = {
      Authorization: `Bearer ${this.apiKey()}`,
      "Content-Type": "application/json",
    };

    const body = {
      model: agent.model,
      messages: translateMessages(messages, agent.systemPrompt),
      tools: translateTools(agent),
      max_tokens: agent.maxTokens,
      stream: true,
    };

    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), TIMEOUT_MS * 2);

    let response: Response;
    try {
      response = await fetch(this.url(), {
        method: "POST",
        headers,
        body: JSON.stringify(body),
        signal: controller.signal,
      });
    } catch (err: unknown) {
      clearTimeout(timeoutId);
      if (err instanceof Error && err.name === "AbortError") {
        throw new Error(`Stream request timeout after ${TIMEOUT_MS * 2}ms`);
      }
      throw err;
    }
    clearTimeout(timeoutId);

    if (!response.ok) {
      const errorData = await response.json();
      throw new Error(
        `OpenRouter stream error: ${response.status} - ${JSON.stringify(errorData)}`,
      );
    }

    if (!response.body) {
      throw new Error("No response body for stream");
    }

    const reader = response.body.getReader();
    const decoder = new TextDecoder();
    let buffer = "";
    const toolCalls: Map<
      number,
      { id: string; name: string; args: string }
    > = new Map();
    let finishReason: string | null = null;
    let inputTokens = 0;
    let outputTokens = 0;

    try {
      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        buffer += decoder.decode(value, { stream: true });
        const lines = buffer.split("\n");
        // La última línea puede estar incompleta
        buffer = lines.pop() ?? "";

        let streamDone = false;
        for (const line of lines) {
          const trimmed = line.trim();
          if (!trimmed || !trimmed.startsWith("data: ")) continue;
          const data = trimmed.slice(6);
          if (data === "[DONE]") {
            finishReason = finishReason ?? "stop";
            streamDone = true;
            break; // fin del stream: cortamos YA. Si seguimos, reader.read()
            // queda bloqueado hasta que el server cierre el socket (~90s).
          }

          let parsed: Record<string, unknown>;
          try {
            parsed = JSON.parse(data);
          } catch {
            continue;
          }

          // Acumular usage si viene en el chunk
          const usage = parsed.usage as Record<string, number> | undefined;
          if (usage) {
            inputTokens = usage.prompt_tokens ?? inputTokens;
            outputTokens = usage.completion_tokens ?? outputTokens;
          }

          const choices = parsed.choices as Array<Record<string, unknown>> | undefined;
          if (!choices || choices.length === 0) continue;

          const delta = choices[0].delta as Record<string, unknown> | undefined;
          if (!delta) continue;

          const finish = choices[0].finish_reason as string | undefined;
          if (finish) finishReason = finish;

          // Ignorar deltas que no son ni texto ni tool_calls 
          // (thinking, reasoning_content, redacted_thinking, etc.)
          const deltaType = delta.type as string | undefined;
          if (deltaType === "thinking" || deltaType === "redacted_thinking") {
            continue;
          }
          if (!delta.content && !delta.tool_calls) {
            // Podría ser reasoning_content u otro bloque no textual
            continue;
          }

          // Texto
          if (delta.content && typeof delta.content === "string") {
            yield { type: "text", text: delta.content };
          }

          // Tool calls en delta
          const tc = delta.tool_calls as Array<Record<string, unknown>> | undefined;
          if (Array.isArray(tc)) {
            for (const t of tc) {
              const idx = t.index as number;
              if (!toolCalls.has(idx)) {
                toolCalls.set(idx, {
                  id: (t.id as string) ?? "",
                  name: (t.function as Record<string, string>)?.name ?? "",
                  args: "",
                });
              }
              const entry = toolCalls.get(idx)!;
              if (t.id) entry.id = t.id as string;
              const fn = t.function as Record<string, string> | undefined;
              if (fn?.name) entry.name = fn.name;
              if (fn?.arguments) entry.args += fn.arguments;
            }
          }
        }
        if (streamDone) break; // cortar el while externo al ver [DONE]
      }
    } finally {
      reader.releaseLock();
    }

    // Después del stream, emitir tool_use completos
    for (const [, tc] of toolCalls) {
      let input: unknown = {};
      try {
        input = tc.args ? JSON.parse(tc.args) : {};
      } catch {
        logger.warn("Malformed stream tool call arguments", { args: tc.args });
      }
      yield { type: "tool_use", id: tc.id, name: tc.name, input };
    }

    const stopReason: "end_turn" | "tool_use" | "max_tokens" =
      finishReason === "tool_calls"
        ? "tool_use"
        : finishReason === "length"
          ? "max_tokens"
          : "end_turn";

    const cost = calculateCost("", inputTokens, outputTokens);

    yield {
      type: "done",
      stop_reason: stopReason,
      usage: { input_tokens: inputTokens, output_tokens: outputTokens },
      cost,
    };
  }
}

export { OpenRouterProvider };

import { AgentConfig } from "../agent-config.js";
import { Message } from "../message.js";

type LLMProviderConstructorProps = {
  apiKey: string;
  url: string;
};

// ── Tipos compartidos entre providers ────────────────────────────────────────

type TextBlock = { type: "text"; text: string };
type ToolUseBlock = { type: "tool_use"; id: string; name: string; input: unknown };
type Block = TextBlock | ToolUseBlock;

type LLMResponse = {
  content: Block[];
  stop_reason: "end_turn" | "tool_use" | "max_tokens";
  usage: { input_tokens: number; output_tokens: number };
  cost: number; // USD
};

/** Eventos que emite el stream de callStream */
type StreamEvent =
  | { type: "text"; text: string }
  | { type: "tool_use"; id: string; name: string; input: unknown }
  | {
      type: "done";
      stop_reason: "end_turn" | "tool_use" | "max_tokens";
      usage: { input_tokens: number; output_tokens: number };
      cost: number;
    };

// ── Precios OpenRouter por millón de tokens (USD) ────────────────────────────

const MODEL_PRICING: Record<string, { input: number; output: number }> = {
  // Claude 4 / 4.5
  "anthropic/claude-haiku-4-5": { input: 0.80, output: 4.00 },
  "anthropic/claude-sonnet-4": { input: 3.00, output: 15.00 },
  "anthropic/claude-opus-4": { input: 15.00, output: 75.00 },
  // Claude 3.5
  "anthropic/claude-3.5-haiku": { input: 0.80, output: 4.00 },
  "anthropic/claude-3.5-sonnet": { input: 3.00, output: 15.00 },
  "anthropic/claude-3-opus": { input: 15.00, output: 75.00 },
};

function calculateCost(model: string, inputTokens: number, outputTokens: number): number {
  let pricing = MODEL_PRICING[model];
  if (!pricing) {
    for (const [key, p] of Object.entries(MODEL_PRICING)) {
      // Match exacto de la clave completa
      if (model === key) {
        pricing = p;
        break;
      }
      // Match por prefijo: el modelo empieza con la clave (ej: "anthropic/claude-...")
      if (model.startsWith(key)) {
        pricing = p;
        break;
      }
      // Match sin el prefijo del proveedor: "claude-haiku-4-5" vs "anthropic/claude-haiku-4-5"
      const afterSlash = key.includes("/") ? key.split("/").slice(1).join("/") : key;
      if (model.startsWith(afterSlash)) {
        pricing = p;
        break;
      }
    }
  }
  if (!pricing) return 0; // modelo desconocido, no estimamos

  const inputCost = (inputTokens / 1_000_000) * pricing.input;
  const outputCost = (outputTokens / 1_000_000) * pricing.output;
  return inputCost + outputCost;
}

// ── Provider abstracto ───────────────────────────────────────────────────────

abstract class LLMProvider {
  #apiKey: string;
  #url: string;

  constructor({ apiKey, url }: LLMProviderConstructorProps) {
    this.#apiKey = apiKey;
    this.#url = url;
  }

  protected apiKey() {
    return this.#apiKey;
  }

  protected url() {
    return this.#url;
  }

  abstract call(messages: Message[], agent: AgentConfig): Promise<LLMResponse>;

  /** Versión streaming: devuelve un async generator de eventos. */
  abstract callStream(
    messages: Message[],
    agent: AgentConfig,
  ): AsyncGenerator<StreamEvent>;
}

export { Block, LLMProvider, LLMResponse, StreamEvent, TextBlock, ToolUseBlock, calculateCost };

import { execSync } from "child_process";
import { Tool } from "./tool.js";
import { logger } from "../logger.js";

type BashInput = { command: string };

const TIMEOUT_MS = 30_000; // matar comandos colgados a los 30s
const MAX_BUFFER = 10 * 1024 * 1024; // 10MB de stdout/stderr

// Esto NO es un sandbox: es un guardarraíl best-effort contra los
// errores más groseros. Un comando malicioso decidido lo puede saltar.
// Para aislamiento real haría falta correr en un contenedor/VM.
const BLOCKED_PATTERNS = [
  /\brm\s+-[a-z]*[rf]/i, // rm con -r o -f en cualquier orden/combinación
  /:\s*\(\s*\)\s*\{.*:.*\|.*:.*\}/, // fork bomb
  />\s*\/dev\/(sd|nvme|disk|hd)/i, // escritura directa a un disco
  /\bmkfs\b/i, // formatear un filesystem
  /\bdd\b.*\bof=\/dev\//i, // dd hacia un device
  /\b(shutdown|reboot|halt|poweroff)\b/i, // apagar/reiniciar la máquina
];

// Patrones que involucran archivos .env (lectura o escritura)
const ENV_ACCESS_PATTERNS = [
  /(^|[|&;`\s])(cat|head|tail|less|more|bat|nl|od|strings)\s+.*\.env\b/i,
  /(^|[|&;`\s])(cp|mv)\s+.*\.env\b/i,
  /(^|[|&;`\s])(cp|mv)\s+\S+\s+.*\.env\b/i,
  />>>?\s*.*\.env\b/i,        // > .env, >> .env
  /(^|[|&;`\s])echo\s+.*>>>?\s*.*\.env\b/i,
  /(^|[|&;`\s])tee\s+.*\.env\b/i,
  /(^|[|&;`\s])(grep|rg|awk|sed|cut|sort|uniq|diff|comm|join|paste)\s+.*\.env\b/i,
  /\.env[\s'"]*$/i,            // cualquier comando cuyo último arg sea .env
];

export class BashTool extends Tool<BashInput, string> {
  constructor() {
    super({
      name: "bash",
      description: "Ejecuta un comando bash y devuelve stdout y stderr",
      schema: {
        type: "object",
        properties: {
          command: {
            type: "string",
            description: "El comando bash a ejecutar",
          },
        },
        required: ["command"],
      },
    });
  }

  private isCommandBlocked(command: string): boolean {
    return BLOCKED_PATTERNS.some((pattern) => pattern.test(command))
      || ENV_ACCESS_PATTERNS.some((pattern) => pattern.test(command));
  }

  execute({ command }: BashInput): string {
    try {
      if (!command || typeof command !== "string") {
        logger.error("Invalid bash command input", { command });
        return "Error: command must be a non-empty string";
      }

      if (this.isCommandBlocked(command)) {
        logger.warn("Blocked dangerous command", { command });
        return "Error: This command is blocked for security reasons";
      }

      logger.info("Executing bash command", { command });
      const result = execSync(command, {
        encoding: "utf-8",
        timeout: TIMEOUT_MS,
        maxBuffer: MAX_BUFFER,
      });
      logger.info("Command executed successfully");
      return result;
    } catch (err: unknown) {
      const error = err as { code?: string; signal?: string; stderr?: string; stdout?: string; message?: string };
      if (error.code === "ETIMEDOUT" || error.signal === "SIGTERM") {
        const msg = `Error: command timed out after ${TIMEOUT_MS}ms`;
        logger.warn("Bash command timed out", { command });
        return msg;
      }
      const errorMsg = error.stderr || error.stdout || error.message || String(err);
      logger.error("Bash command failed", { command, error: errorMsg });
      return errorMsg;
    }
  }
}

import { stdin, stdout } from "process";
import { InputComponent } from "./component.js";
import { decodeKey } from "./decodeKey.js";
import { disableRawMode } from "./terminal.js";

// ── Secuencias de escape ANSI ─────────────────────────────────────────

const CSI = "\x1b[";
const CUU = (n: number) => `${CSI}${n}A`; // Cursor Up n rows
const CUF = (n: number) => `${CSI}${n}C`; // Cursor Forward n cols
const ED0 = `${CSI}0J`; // Erase Display: cursor → end
const CR = "\r";
const LF = "\n";
const CURSOR_SHOW = `${CSI}?25h`;

const PASTE_START = "\x1b[200~";
const PASTE_END = "\x1b[201~";

/**
 * Renderer persistente del prompt fijo abajo. A diferencia del viejo run()
 * (que era transitorio: manejaba un componente, lo commiteaba y moría), Screen
 * mantiene el componente vivo en la última línea y expone:
 *
 *   - readLine(component): espera input sin destruir el componente.
 *   - printAbove(text):    imprime text en el scrollback, ARRIBA del editor.
 *   - setStatus(text):     línea de estado (spinner) justo encima del editor.
 *
 * Todo el output del programa (texto del agente, tools, métricas, comandos)
 * debe pasar por printAbove; escribir directo a stdout pisaría el editor.
 *
 * Posicionamiento RELATIVO (inmune a scroll): nos movemos siempre relativo a
 * donde está el cursor, nunca con posiciones absolutas (\x1b7/\x1b8).
 */
class Screen {
  #live: InputComponent<unknown> | null = null;
  #status: string | null = null;
  #ephemeral: string | null = null;
  #reading = false;
  #resolve: ((result: unknown) => void) | null = null;

  #prevRows = 0; // filas que ocupó la región viva en el último render
  #prevCursorRow = 0; // fila (0-based) donde quedó el cursor

  #busy = false; // lock para evitar que setStatus redibuje durante printAbove
  #statusDirty = false; // setStatus cambió estando busy → redibujar al unlock
  #pasteBuffer: string | null = null;
  #paddingRight: number;

  constructor(paddingRight: number = 0) {
    this.#paddingRight = paddingRight;
    stdin.on("data", this.#onData);
  }

  /** Adquirir lock de escritura. Mientras está tomado, setStatus solo
   * actualiza #status en memoria, no redibuja (evita race condition con
   * el timer del spinner durante printAbove/writeEphemeral). */
  #lock(): void {
    this.#busy = true;
  }

  #unlock(): void {
    this.#busy = false;
    if (this.#statusDirty) {
      this.#statusDirty = false;
      this.#redraw();
    }
  }

  /** Espera a que el componente termine (isDone). Lo deja vivo abajo. */
  readLine<T>(component: InputComponent<T>): Promise<T> {
    this.#live = component as InputComponent<unknown>;
    this.#reading = true;
    this.#redraw();
    return new Promise<T>((resolve) => {
      this.#resolve = (result) => resolve(result as T);
    });
  }

  /** Imprime text en el scrollback, por encima de la región viva.
   * El efímero no se pierde: se limpia momentáneamente y se redibuja
   * abajo del texto commiteado. */
  printAbove(text: string): void {
    this.#lock();
    this.#clearLive();
    // Considerar "vacío" después de strippear ANSI, no por text.length
    if (stripAnsi(text).trim().length > 0) {
      const out = this.#wrapIfNeeded(text);
      stdout.write(out);
      if (!out.endsWith("\n")) stdout.write(LF);
    }
    this.#renderLive();
    this.#unlock();
  }

  #wrapIfNeeded(text: string): string {
    if (this.#paddingRight <= 0) return text;
    const maxWidth = (stdout.columns ?? 80) - this.#paddingRight;
    if (maxWidth < 20) return text; // no vale la pena wrappear columnas muy angostas
    return wrapText(text, maxWidth);
  }

  /**
   * Texto efímero: se sobrescribe en cada llamada. Truncado a 1 línea
   * visual (stdout.columns), sin wrapping. Es parte de la región viva.
   */
  writeEphemeral(text: string): void {
    this.#lock();
    this.#ephemeral = text.length > 0 && stripAnsi(text).trim().length > 0
      ? truncateEphemeral(text)
      : null;
    this.#redraw();
    this.#unlock();
  }

  /** Limpia el texto efímero sin dejar rastro. */
  clearEphemeral(): void {
    this.#lock();
    this.#ephemeral = null;
    this.#redraw();
    this.#unlock();
  }

  /** Redibuja la región viva en el lugar (útil tras escribir al scrollback).
   * Toma el lock para que el timer del spinner no interfiera. */
  redrawLive(): void {
    this.#lock();
    this.#clearLive();
    this.#renderLive();
    this.#unlock();
  }

  /** Setea (o limpia con null) la línea de estado encima del editor. */
  setStatus(text: string | null): void {
    this.#status = text;
    if (!this.#busy) {
      this.#redraw();
    } else {
      this.#statusDirty = true;
    }
  }

  // ── interno ───────────────────────────────────────────────────────────

  /** Render combinado: efímero (si hay) + status (si hay) + editor. */
  #composeRender(): { out: string; cursorRow: number; cursorCol: number } {
    const lines: string[] = [];
    const ephemeralRows = this.#ephemeral !== null ? 1 : 0;
    const statusRows = this.#status !== null ? 1 : 0;

    if (ephemeralRows) lines.push(this.#ephemeral as string);
    if (statusRows) lines.push(this.#status as string);
    lines.push(this.#live ? this.#live.render() : "");

    const out = lines.join("\n");

    let cursorRow = out.split("\n").length - 1;
    let cursorCol = 0;
    if (this.#live?.getCursorPosition) {
      const cp = this.#live.getCursorPosition();
      cursorRow = cp.row + ephemeralRows + statusRows;
      cursorCol = cp.col;
    }
    return { out, cursorRow, cursorCol };
  }

  /** Sube al tope de la región viva y limpia de ahí hacia abajo (relativo). */
  #clearLive(): void {
    if (this.#prevCursorRow > 0) stdout.write(CUU(this.#prevCursorRow));
    stdout.write(CR);
    stdout.write(ED0);
  }

  /** Escribe la región viva en la posición actual del cursor y lo ubica. */
  #renderLive(): void {
    const { out, cursorRow, cursorCol } = this.#composeRender();
    stdout.write(out);
    const rows = out.split("\n").length;
    const up = rows - 1 - cursorRow;
    if (up > 0) stdout.write(CUU(up));
    stdout.write(CR + (cursorCol > 0 ? CUF(cursorCol) : ""));
    this.#prevRows = rows;
    this.#prevCursorRow = cursorRow;
  }

  /** Redibujo en el lugar (tecla, cambio de estado). */
  #redraw(): void {
    this.#clearLive();
    this.#renderLive();
  }

  #onData = (raw: string): void => {
    if (!this.#reading) return; // ignoramos input mientras el agente trabaja

    if (this.#pasteBuffer !== null) {
      this.#pasteBuffer += raw;
      if (this.#pasteBuffer.includes(PASTE_END)) {
        const text = this.#pasteBuffer
          .replace(/^\x1b\[200~/, "")
          .replace(/\x1b\[201~$/, "");
        this.#pasteBuffer = null;
        this.#processKey(text);
      }
      return;
    }

    if (raw.includes(PASTE_START)) {
      const idx = raw.indexOf(PASTE_START);
      if (idx > 0) this.#processKey(raw.slice(0, idx));
      this.#pasteBuffer = raw.slice(idx);
      if (this.#pasteBuffer.includes(PASTE_END)) {
        const text = this.#pasteBuffer
          .replace(/^\x1b\[200~/, "")
          .replace(/\x1b\[201~$/, "");
        this.#pasteBuffer = null;
        this.#processKey(text);
      }
      return;
    }

    this.#processKey(raw);
  };

  #processKey(keyStr: string): void {
    const key = decodeKey(keyStr);

    if (key.type === "ctrl" && key.key === "c") {
      stdout.write(CURSOR_SHOW);
      stdin.removeListener("data", this.#onData);
      disableRawMode();
      process.exit(0);
    }

    if (!this.#live) return;

    this.#live.handleKey(key);
    this.#redraw();

    if (this.#live.isDone()) {
      this.#reading = false;
      const result = this.#live.getResult();
      const resolve = this.#resolve;
      this.#resolve = null;
      resolve?.(result);
    }
  }
}

// ── Helpers de ANSI ──────────────────────────────────────────────────────────

// eslint-disable-next-line no-control-regex
const ANSI_RE = /\x1b\[[0-9;]*m/g;

function stripAnsi(text: string): string {
  return text.replace(ANSI_RE, "");
}

/** Trunca text a stdout.columns caracteres visibles (ignorando ANSI),
 *  para garantizar que el efímero nunca wrapee. */
function truncateEphemeral(text: string): string {
  const width = (stdout.columns ?? 80) - 1; // -1 por margen de seguridad
  const stripped = stripAnsi(text);
  if (stripped.length <= width) return text;

  // Avanzar por el string original, salteando secuencias ANSI
  let visible = 0;
  let i = 0;
  while (i < text.length && visible < width) {
    const match = text.slice(i).match(/^\x1b\[[0-9;]*m/);
    if (match) {
      i += match[0].length;
      continue;
    }
    visible++;
    i++;
  }
  return text.slice(0, i);
}

/**
 * Word-wrap consciente de ANSI. Respeta saltos de línea existentes y
 * re-aplica códigos de estilo en cada línea resultante para que no se
 * pierdan al cortar.
 */
function wrapText(text: string, maxWidth: number): string {
  const lines = text.split("\n");
  const result: string[] = [];
  for (const line of lines) {
    const wrapped = wrapLine(line, maxWidth);
    result.push(...wrapped);
  }
  return result.join("\n");
}

/** Secuencia ANSI de apertura al inicio de un string, ej: "\x1b[2m". */
const ANSI_LEADING_RE = /^\x1b\[[0-9;]*m/;

function extractLeadingAnsi(s: string): string {
  const m = s.match(ANSI_LEADING_RE);
  return m ? m[0] : "";
}

function extractTrailingAnsi(s: string): string {
  // El cierre de estilo que usamos siempre es \x1b[0m
  if (s.endsWith("\x1b[0m")) return "\x1b[0m";
  return "";
}

function wrapLine(line: string, maxWidth: number): string[] {
  const visibleLen = stripAnsi(line).length;
  if (visibleLen <= maxWidth) return [line];

  const leading = extractLeadingAnsi(line);
  const trailing = extractTrailingAnsi(line);

  // Quitar apertura y cierre para trabajar con el texto limpio
  let inner = line;
  if (leading) inner = inner.slice(leading.length);
  if (trailing) inner = inner.slice(0, inner.length - trailing.length);

  const result: string[] = [];

  while (inner.length > 0) {
    if (stripAnsi(inner).length <= maxWidth) {
      result.push(leading + inner + trailing);
      break;
    }

    // Buscar el último espacio dentro del límite visible
    let spaceIdx = -1;
    let visibleCount = 0;
    for (let i = 0; i < inner.length && visibleCount < maxWidth; i++) {
      const ansiMatch = inner.slice(i).match(ANSI_LEADING_RE);
      if (ansiMatch) {
        i += ansiMatch[0].length - 1;
        continue;
      }
      if (inner[i] === " ") spaceIdx = i;
      visibleCount++;
    }

    let cutIdx: number;
    let skip: number; // cuántos chars saltar al pasar a la siguiente línea

    if (spaceIdx > 0) {
      // Cortar en el espacio: no lo incluimos en la línea, y lo saltamos
      cutIdx = spaceIdx;
      skip = 1; // saltar el espacio mismo
    } else {
      // No hay espacio: cortar justo en maxWidth caracteres visibles
      visibleCount = 0;
      cutIdx = 0;
      for (let i = 0; i < inner.length && visibleCount < maxWidth; i++) {
        const ansiMatch = inner.slice(i).match(ANSI_LEADING_RE);
        if (ansiMatch) {
          i += ansiMatch[0].length - 1;
          continue;
        }
        visibleCount++;
        cutIdx = i + 1;
      }
      skip = 0; // no saltar nada, continuación pegada
    }

    result.push(leading + inner.slice(0, cutIdx) + trailing);
    inner = inner.slice(cutIdx + skip);
  }

  return result.length > 0 ? result : [line];
}

export { Screen, stripAnsi, truncateEphemeral, wrapText };

import { AgentConfig } from "../agent-config.js";
import { logger } from "../logger.js";
import { Message } from "../message.js";
import { Block, calculateCost, LLMProvider, LLMResponse, StreamEvent } from "./llm-provider.js";

const TIMEOUT_MS = 60000;
const MAX_RETRIES = 3;
const INITIAL_BACKOFF_MS = 1000;

type AnthropicContentBlock =
  | { type: "text"; text: string }
  | { type: "tool_use"; id: string; name: string; input: unknown };

type AnthropicResponse = {
  id: string;
  type: "message";
  role: "assistant";
  content: AnthropicContentBlock[];
  stop_reason: "end_turn" | "max_tokens" | "tool_use";
  usage: { input_tokens: number; output_tokens: number };
};

class AnthropicProvider extends LLMProvider {
  constructor(apiKey: string) {
    super({
      apiKey,
      url: "https://api.anthropic.com/v1/messages",
    });
  }

  private async sleep(ms: number): Promise<void> {
    return new Promise((resolve) => setTimeout(resolve, ms));
  }

  private parseResponse(data: AnthropicResponse, model: string): LLMResponse {
    const content: Block[] = data.content.map((block) => {
      if (block.type === "text") {
        return { type: "text", text: block.text };
      }
      return {
        type: "tool_use",
        id: block.id,
        name: block.name,
        input: block.input,
      };
    });

    return {
      content,
      stop_reason: data.stop_reason === "tool_use" ? "tool_use" : data.stop_reason,
      usage: {
        input_tokens: data.usage.input_tokens,
        output_tokens: data.usage.output_tokens,
      },
      cost: calculateCost(model, data.usage.input_tokens, data.usage.output_tokens),
    };
  }

  private async callWithRetry(
    messages: Message[],
    agent: AgentConfig,
    attempt: number = 1,
  ): Promise<LLMResponse> {
    const headers: Record<string, string> = {
      "x-api-key": this.apiKey(),
      "anthropic-version": "2023-06-01",
      "content-type": "application/json",
    };

    const body: Record<string, unknown> = {
      model: agent.model,
      system: agent.systemPrompt,
      max_tokens: agent.maxTokens,
      messages,
      tools: Object.values(agent.tools()).map((t) => t.toJSON()),
    };

    try {
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), TIMEOUT_MS);

      const response = await fetch(this.url(), {
        method: "POST",
        headers,
        body: JSON.stringify(body),
        signal: controller.signal,
      });

      clearTimeout(timeoutId);

      if (response.ok) {
        const data = (await response.json()) as AnthropicResponse;
        logger.info("API call successful");
        return this.parseResponse(data, agent.model);
      }

      if (response.status === 401) {
        const error = "Invalid API key";
        logger.error(error);
        throw new Error(error);
      }

      if (response.status === 429 || response.status === 529) {
        if (attempt < MAX_RETRIES) {
          const backoffMs = INITIAL_BACKOFF_MS * Math.pow(2, attempt - 1);
          logger.warn(
            `Rate limited. Retrying in ${backoffMs}ms (attempt ${attempt}/${MAX_RETRIES})`,
          );
          await this.sleep(backoffMs);
          return this.callWithRetry(messages, agent, attempt + 1);
        }
      }

      const errorData = await response.json();
      logger.error(`API error (${response.status})`, errorData);
      throw new Error(
        `Anthropic API error: ${response.status} - ${JSON.stringify(errorData)}`,
      );
    } catch (err: unknown) {
      if (err instanceof Error && err.name === "AbortError") {
        logger.error("API request timeout");
        throw new Error(`Request timeout after ${TIMEOUT_MS}ms`);
      }
      throw err;
    }
  }

  async call(messages: Message[], agent: AgentConfig): Promise<LLMResponse> {
    logger.info("Making API call to Anthropic");
    return this.callWithRetry(messages, agent);
  }

  async *callStream(
    _messages: Message[],
    _agent: AgentConfig,
  ): AsyncGenerator<StreamEvent> {
    throw new Error("AnthropicProvider does not support streaming yet");
  }
}

export { AnthropicProvider };

import { cyan, dim, gray } from "../theme.js";
import { Screen } from "../screen.js";

interface DisplayText {
  display(text: string): void;
}

/**
 * Los display imprimen ARRIBA de la región viva (vía screen.printAbove), no
 * directo a stdout, así no pisan el editor fijo abajo. Cada uno aplica su
 * estilo.
 */
class DisplayAssistantText implements DisplayText {
  #screen: Screen;
  #buffer = "";
  #streaming = false;

  constructor(screen: Screen) {
    this.#screen = screen;
  }

  /** Muestra un chunk de texto (modo streaming). Acumula en buffer,
   * flushea líneas completas al scrollback (seguro sin importar el largo)
   * y mantiene la línea en progreso como texto efímero (1-2 líneas,
   * siempre cabe en viewport -> CUU seguro). */
  displayStream(chunk: string): void {
    this.#streaming = true;
    this.#buffer += chunk;

    const lines = this.#buffer.split("\n");
    const complete = lines.slice(0, -1);
    const partial = lines[lines.length - 1];

    // Flushear líneas completas al scrollback
    if (complete.length > 0) {
      this.#screen.clearEphemeral();
      for (const line of complete) {
        this.#screen.printAbove(dim(line));
      }
    }

    // Mostrar la linea en progreso como texto efimero
    this.#screen.writeEphemeral(dim(partial));
    this.#buffer = partial;
  }

  /** Cierra el streaming: limpia el texto efimero y flushea el resto. */
  endStream(): void {
    if (!this.#streaming) return;
    this.#streaming = false;
    this.#screen.clearEphemeral();
    if (this.#buffer.length > 0) {
      this.#screen.printAbove(dim(this.#buffer));
    }
    this.#buffer = "";
  }

  display(text: string): void {
    this.#screen.printAbove(dim(text));
  }
}

/**
 * Tool call compacto: "> read src/index.ts" o "> bash 'git status'".
 * Verbose: igual que compacto (el input ya es visible).
 */
class DisplayToolCall {
  #screen: Screen;
  constructor(screen: Screen) {
    this.#screen = screen;
  }

  call(name: string, input: unknown, _verbose: boolean): void {
    const desc = this.#describeInput(name, input);
    this.#screen.printAbove(cyan(`> ${desc}`));
  }

  #describeInput(name: string, input: unknown): string {
    if (!input || typeof input !== "object") return name;
    const obj = input as Record<string, unknown>;

    // Extraer el argumento más descriptivo según la tool
    switch (name) {
      case "read":
        return `read ${this.#pathStr(obj)}`;
      case "write":
        return `write ${this.#pathStr(obj)}`;
      case "edit":
        return `edit ${this.#pathStr(obj)}`;
      case "bash":
        if (typeof obj.command === "string") {
          return `bash ${this.#truncateCmd(obj.command)}`;
        }
        return "bash";
      case "grep":
        return `grep "${obj.pattern ?? "?"}" ${this.#pathStr(obj)}`;
      default:
        return name;
    }
  }

  #pathStr(obj: Record<string, unknown>): string {
    return typeof obj.path === "string" ? obj.path : "?";
  }

  #truncateCmd(cmd: string): string {
    return cmd.length > 70 ? `'${cmd.slice(0, 67)}...'` : `'${cmd}'`;
  }
}

/**
 * Tool result: en modo compacto muestra un resumen de una línea.
 * En modo verbose, vuelca el contenido completo.
 */
class DisplayToolResult {
  #screen: Screen;
  constructor(screen: Screen) {
    this.#screen = screen;
  }

  result(output: string, verbose: boolean, rawOutput?: string): void {
    const summarySource = rawOutput ?? output;
    if (verbose) {
      if (output.length > 0) {
        this.#screen.printAbove(gray(output));
      }
      return;
    }

    const summary = this.#summarize(summarySource);
    this.#screen.printAbove(gray(`  = ${summary}`));
  }

  #summarize(output: string): string {
    if (!output || output.trim() === "") return "vacío";

    const lines = output.split("\n");
    const chars = output.length;
    const L = lines.length;

    // Resúmenes por tipo de contenido
    if (L === 1 && chars < 120) {
      return output.trim();
    }

    if (output.startsWith("Error")) {
      // Errores: mostrar la primera línea (el mensaje principal)
      return output.split("\n")[0].trim();
    }

    const sizeStr = chars >= 1000
      ? `${(chars / 1000).toFixed(1)}K`
      : `${chars}`;

    return `${L} líneas · ${sizeStr} chars`;
  }
}

export { DisplayAssistantText, DisplayToolCall, DisplayToolResult };

import { describe, it, expect, beforeEach } from "vitest";
import { Runner } from "../runner.js";
import { AgentConfig } from "../agent-config.js";
import { LLMProvider, LLMResponse, StreamEvent } from "../providers/llm-provider.js";
