import { ReadTool } from "../tools/read.js";
import { Message } from "../message.js";

// ── Mock LLM Provider ────────────────────────────────────────────────────────

class MockLLMProvider extends LLMProvider {
  #responses: LLMResponse[];
  #callCount = 0;

  constructor(responses: LLMResponse[]) {
    super({ apiKey: "mock-key", url: "http://mock" });
    this.#responses = responses;
  }

  async call(_messages: Message[], _agent: AgentConfig): Promise<LLMResponse> {
    const resp = this.#responses[this.#callCount % this.#responses.length];
    this.#callCount++;
    return resp;
  }

  async *callStream(_messages: Message[], _agent: AgentConfig): AsyncGenerator<StreamEvent> {
    const resp = this.#responses[this.#callCount % this.#responses.length];
    this.#callCount++;

    for (const block of resp.content) {
      if (block.type === "text") {
        yield { type: "text", text: block.text };
      }
      if (block.type === "tool_use") {
        yield { type: "tool_use", id: block.id, name: block.name, input: block.input };
      }
    }

    yield {
      type: "done",
      stop_reason: resp.stop_reason,
      usage: resp.usage,
      cost: resp.cost,
    };
  }
}

// ── Helpers ──────────────────────────────────────────────────────────────────

function mockAgent(): AgentConfig {
  const agent = new AgentConfig({
    systemPrompt: "Test",
    model: "claude-haiku-4-5-20251001",
    maxTokens: 1024,
  });
  agent.addTool(new BashTool());
  agent.addTool(new ReadTool());
  return agent;
}

function textResponse(text: string): LLMResponse {
  return {
    content: [{ type: "text", text }],
    stop_reason: "end_turn",
    usage: { input_tokens: 10, output_tokens: 5 },
    cost: 0.0001,
  };
}

function toolUseResponse(
  toolCalls: Array<{ id: string; name: string; input: unknown }>,
): LLMResponse {
  return {
    content: toolCalls.map((tc) => ({
      type: "tool_use" as const,
      ...tc,
    })),
    stop_reason: "tool_use",
    usage: { input_tokens: 20, output_tokens: 10 },
    cost: 0.0002,
  };
}

function mixedResponse(
  text: string,
  toolCalls: Array<{ id: string; name: string; input: unknown }>,
): LLMResponse {
  return {
    content: [
      { type: "text" as const, text },
      ...toolCalls.map((tc) => ({ type: "tool_use" as const, ...tc })),
    ],
    stop_reason: "tool_use",
    usage: { input_tokens: 30, output_tokens: 15 },
    cost: 0.0003,
  };
}

async function collectEvents(runner: Runner, context: Message[]): Promise<Array<{ type: string; name?: string }>> {
  const events: Array<{ type: string; name?: string }> = [];
  for await (const event of runner.run(context)) {
    events.push({ type: event.type, name: "name" in event ? (event as { name: string }).name : undefined });
  }
  return events;
}

// ── Tests ────────────────────────────────────────────────────────────────────

describe("Runner", () => {
  describe("single text response", () => {
    it("should emit text and state events for a simple text response", async () => {
      const provider = new MockLLMProvider([textResponse("Hello!")]);
      const runner = new Runner({ llmProvider: provider, agentConfig: mockAgent() });
      const context: Message[] = [{ role: "user", content: "Hi" }];

      const events = await collectEvents(runner, context);
      expect(events.some((e) => e.type === "text_stream")).toBe(true);
      expect(events.some((e) => e.type === "text_stream_end")).toBe(true);
      expect(events.some((e) => e.type === "state")).toBe(true);
    });

    it("should not emit tool_use events for text-only response", async () => {
      const provider = new MockLLMProvider([textResponse("Done")]);
      const runner = new Runner({ llmProvider: provider, agentConfig: mockAgent() });
      const context: Message[] = [{ role: "user", content: "x" }];

      const events = await collectEvents(runner, context);
      expect(events.some((e) => e.type === "tool_use")).toBe(false);
      expect(events.some((e) => e.type === "tool_result")).toBe(false);
    });
  });

  describe("tool use response", () => {
    it("should execute tool and emit tool_result", async () => {
      // 1st: tool_use, 2nd: end_turn
      const provider = new MockLLMProvider([
        toolUseResponse([{ id: "t1", name: "bash", input: { command: "echo hello" } }]),
        textResponse("Tool executed."),
      ]);
      const runner = new Runner({ llmProvider: provider, agentConfig: mockAgent() });
      const context: Message[] = [{ role: "user", content: "run echo" }];

      const events = await collectEvents(runner, context);
      expect(events.some((e) => e.type === "tool_use")).toBe(true);
      expect(events.some((e) => e.type === "tool_result")).toBe(true);
    });

    it("should handle unknown tool gracefully", async () => {
      const provider = new MockLLMProvider([
        toolUseResponse([{ id: "t1", name: "nonexistent_tool", input: {} }]),
        textResponse("Done"),
      ]);
      const runner = new Runner({ llmProvider: provider, agentConfig: mockAgent() });
      const context: Message[] = [{ role: "user", content: "use unknown tool" }];

      const events = await collectEvents(runner, context);
      expect(events.some((e) => e.type === "tool_result")).toBe(true);
    });

    it("should handle mixed text + tool_use", async () => {
      const provider = new MockLLMProvider([
        mixedResponse("Let me check...", [
          { id: "t1", name: "bash", input: { command: "pwd" } },
        ]),
        textResponse("All done."),
      ]);
      const runner = new Runner({ llmProvider: provider, agentConfig: mockAgent() });
      const context: Message[] = [{ role: "user", content: "where am I?" }];

      const events = await collectEvents(runner, context);
      expect(events.some((e) => e.type === "text_stream")).toBe(true);
      expect(events.some((e) => e.type === "tool_use")).toBe(true);
      expect(events.some((e) => e.type === "tool_result")).toBe(true);
    });
  });

  describe("max_tokens stop reason", () => {
    it("should emit warning text on max_tokens", async () => {
      const provider = new MockLLMProvider([{
        content: [{ type: "text", text: "Partial..." }],
        stop_reason: "max_tokens",
        usage: { input_tokens: 10, output_tokens: 5 },
        cost: 0.0001,
      }]);
      const runner = new Runner({ llmProvider: provider, agentConfig: mockAgent() });
      const context: Message[] = [{ role: "user", content: "big task" }];

      const events: string[] = [];
      for await (const event of runner.run(context)) {
        if (event.type === "text") {
          events.push(event.text);
        }
      }
      const warning = events.find((t) => t.includes("cortó"));
      expect(warning).toBeDefined();
    });
  });

  describe("metrics", () => {
    it("should accumulate token usage and cost", async () => {
      const provider = new MockLLMProvider([
        textResponse("First"),
        textResponse("Second"),
      ]);
      const runner = new Runner({ llmProvider: provider, agentConfig: mockAgent() });
      const context: Message[] = [{ role: "user", content: "multi" }];

      for await (const _event of runner.run(context)) {
        // consume
      }

      const metrics = runner.getMetrics();
      expect(metrics.totalInputTokens).toBeGreaterThan(0);
      expect(metrics.totalOutputTokens).toBeGreaterThan(0);
      expect(metrics.totalCost).toBeGreaterThan(0);
      expect(metrics.totalToolCalls).toBe(0);
      expect(metrics.durationMs).toBeGreaterThanOrEqual(0);
    });

    it("should count tool calls", async () => {
      const provider = new MockLLMProvider([
        toolUseResponse([{ id: "t1", name: "bash", input: { command: "echo a" } }]),
        textResponse("Done"),
      ]);
      const runner = new Runner({ llmProvider: provider, agentConfig: mockAgent() });
      const context: Message[] = [{ role: "user", content: "run cmd" }];

      for await (const _event of runner.run(context)) {
        // consume
      }

      expect(runner.getMetrics().totalToolCalls).toBe(1);
    });
  });

  describe("max steps", () => {
    it("should stop after maxSteps", async () => {
      // Cada respuesta pide tool_use -> el loop consumiría steps hasta el límite
      const responses: LLMResponse[] = [];
      for (let i = 0; i < 20; i++) {
        responses.push(
          toolUseResponse([{ id: `t${i}`, name: "bash", input: { command: "echo x" } }]),
        );
      }
      const provider = new MockLLMProvider(responses);
      const runner = new Runner({
        llmProvider: provider,
        agentConfig: mockAgent(),
        maxSteps: 3,
      });
      const context: Message[] = [{ role: "user", content: "loop" }];

      let toolUseCount = 0;
      for await (const event of runner.run(context)) {
        if (event.type === "tool_use") toolUseCount++;
      }

      // Con maxSteps=3, el loop hace 3 iteraciones de tool_use
      expect(toolUseCount).toBeLessThanOrEqual(3);
    });
  });

  describe("resetMetrics", () => {
    it("should reset all metrics to zero", async () => {
      const provider = new MockLLMProvider([textResponse("Hi")]);
      const runner = new Runner({ llmProvider: provider, agentConfig: mockAgent() });
      const context: Message[] = [{ role: "user", content: "x" }];

      for await (const _event of runner.run(context)) {
        // consume
      }

      runner.resetMetrics();
      const metrics = runner.getMetrics();
      expect(metrics.totalInputTokens).toBe(0);
      expect(metrics.totalOutputTokens).toBe(0);
      expect(metrics.totalToolCalls).toBe(0);
      expect(metrics.totalCost).toBe(0);
    });
  });
});

// tui/terminal.ts
import { stdin, stdout } from "process";

let rawModeEnabled = false;

export function enableRawMode() {
  if (rawModeEnabled) return;
  stdin.setRawMode(true);
  stdin.resume();
  stdin.setEncoding("utf-8");
  stdout.write("\x1b[?2004h"); // bracketed paste on
  rawModeEnabled = true;

  // Restaurar al salir normalmente
  process.on("exit", disableRawMode);

  // Restaurar ante señales catchables (SIGTERM, SIGINT)
  // SIGKILL no es catchable — no hay nada que hacer.
  const onSignal = () => {
    disableRawMode();
    process.exit(1);
  };
  process.on("SIGTERM", onSignal);
  process.on("SIGINT", onSignal);
}

export function disableRawMode() {
  if (!rawModeEnabled) return;
  stdin.setRawMode(false);
  stdout.write("\x1b[?2004l"); // bracketed paste off
  stdout.write("\r\n");        // dejar el cursor en línea nueva
  rawModeEnabled = false;
}

export function isRawModeEnabled() {
  return rawModeEnabled;
}

import { Context } from "../../app-context.js";
import { ModalCommand, ModalPicker } from "../../commands/modal-command.js";
import { CursorPosition, InputComponent } from "../component.js";
import { Key } from "../decodeKey.js";
import { LineEditor } from "./line-editor.js";

type PromptResult =
  | { kind: "submit"; text: string } // input normal o comando no-modal: lo resuelve el loop
  | { kind: "modal"; message?: string }; // un comando modal ya hizo su efecto

type PromptProps = {
  editor: LineEditor;
  ctx: Context;
  modals: Record<string, ModalCommand>;
};

/**
 * Componente raíz del input. Hostea el LineEditor y, para comandos modales
 * (ej: /resume), un SelectList — todo en UNA región viva.
 *
 *   editing  → solo el LineEditor.
 *   picking  → LineEditor + picker debajo.
 *
 * Como el render vuelve a estado y el driver limpia de la región hacia abajo,
 * cancelar el modal (Esc) colapsa la lista solo: el render pasa a ser más corto.
 * Nada se commitea hasta un final de "aceptar"; Esc vuelve a editing con el
 * buffer intacto (por eso el editor expone reopen()).
 */
class Prompt implements InputComponent<PromptResult> {
  #editor: LineEditor;
  #ctx: Context;
  #modals: Record<string, ModalCommand>;
  #mode: "editing" | "picking";
  #picker: ModalPicker | null;
  #activeModal: ModalCommand | null;
  #result: PromptResult | null;
  #done: boolean;

  constructor({ editor, ctx, modals }: PromptProps) {
    this.#editor = editor;
    this.#ctx = ctx;
    this.#modals = modals;
    this.#mode = "editing";
    this.#picker = null;
    this.#activeModal = null;
    this.#result = null;
    this.#done = false;
  }

  handleKey(key: Key): void {
    if (this.#mode === "editing") {
      this.#handleEditing(key);
    } else {
      this.#handlePicking(key);
    }
  }

  #handleEditing(key: Key): void {
    this.#editor.handleKey(key);
    if (!this.#editor.isDone()) return;

    const text = this.#editor.getResult();
    const tokens = text.trim().split(/\s+/);
    // Solo el comando "pelado" (sin args) abre modal; "/resume 3" cae al loop.
    const modal = tokens.length === 1 ? this.#modals[tokens[0]] : undefined;

    if (!modal) {
      this.#result = { kind: "submit", text };
      this.#done = true;
      return;
    }

    const opened = modal.open(this.#ctx);
    if ("message" in opened) {
      // no hay nada que elegir (ej: no hay sesiones guardadas)
      this.#result = { kind: "modal", message: opened.message };
      this.#done = true;
      return;
    }

    // entramos al picker; el editor queda "submitted" pero lo reabrimos si cancela
    this.#picker = opened.picker;
    this.#activeModal = modal;
    this.#mode = "picking";
  }

  #handlePicking(key: Key): void {
    const picker = this.#picker;
    const modal = this.#activeModal;
    if (!picker || !modal) return;

    picker.handleKey(key);
    if (!picker.isDone()) return;

    const value = picker.getResult(); // null = cancelado (Esc)
    this.#picker = null;
    this.#activeModal = null;

    if (value === null) {
      // volver a editar la MISMA línea, con "/resume" intacto
      this.#mode = "editing";
      this.#editor.reopen();
      return;
    }

    const message = modal.apply(this.#ctx, value) || undefined;
    this.#result = { kind: "modal", message };
    this.#mode = "editing"; // que el render final sea solo el editor (la lista se va)
    this.#done = true;
  }

  isDone(): boolean {
    return this.#done;
  }

  getResult(): PromptResult {
    return this.#result ?? { kind: "submit", text: this.#editor.getResult() };
  }

  render(): string {
    const editor = this.#editor.render();
    if (this.#mode === "picking" && this.#picker) {
      return editor + "\n" + this.#picker.render();
    }
    return editor;
  }

  getCursorPosition(): CursorPosition {
    if (this.#mode === "picking" && this.#picker) {
      const editorLines = this.#editor.render().split("\n").length;
      return { row: editorLines + this.#picker.selectedRow(), col: 0 };
    }
    return this.#editor.getCursorPosition();
  }
}

export { Prompt, PromptResult };

import { stdout } from "process";
import { CursorPosition, InputComponent } from "../component.js";
import { Key } from "../decodeKey.js";
import { dim } from "../theme.js";

class LineEditor implements InputComponent<string> {
  #buffer: string;
  #cursor: number; // índice dentro del buffer, 0-based
  #done: boolean;
  #promptStr = "> ";
  #history: string[];
  #historyIndex: number; // -1 = no navegando; 0..len-1 = posición en historia
  #draftBuffer: string; // buffer que se guarda antes de navegar historia
  #draftCursor: number;

  constructor() {
    this.#buffer = "";
    this.#cursor = 0;
    this.#done = false;
    this.#history = [];
    this.#historyIndex = -1;
    this.#draftBuffer = "";
    this.#draftCursor = 0;
  }

  /** Vuelve a modo edición tras un commit, conservando buffer y cursor.
   * Lo usa el Prompt cuando se cancela un modal y hay que seguir editando
   * la misma línea (ej: tipeaste "/resume", se abrió el picker, apretaste Esc). */
  reopen(): void {
    this.#done = false;
  }

  /** Reinicia el estado para un nuevo input (sin perder el historial). */
  reset(): void {
    this.#buffer = "";
    this.#cursor = 0;
    this.#done = false;
    this.#historyIndex = -1;
    this.#draftBuffer = "";
    this.#draftCursor = 0;
  }

  // ---- helpers de línea ----

  /** Índice del inicio de la línea donde está el cursor */
  #lineStart(): number {
    const before = this.#buffer.lastIndexOf("\n", this.#cursor - 1);
    return before === -1 ? 0 : before + 1;
  }

  /** Índice del final de la línea donde está el cursor (apunta al \n o al final) */
  #lineEnd(): number {
    const after = this.#buffer.indexOf("\n", this.#cursor);
    return after === -1 ? this.#buffer.length : after;
  }

  /** Cantidad de líneas en el buffer */
  #lineCount(): number {
    let n = 1;
    for (let i = 0; i < this.#buffer.length; i++) {
      if (this.#buffer[i] === "\n") n++;
    }
    return n;
  }

  /** Número de línea (0-based) donde está el cursor */
  #cursorLine(): number {
    let line = 0;
    for (let i = 0; i < this.#cursor; i++) {
      if (this.#buffer[i] === "\n") line++;
    }
    return line;
  }

  /** Columna (0-based) del cursor dentro de su línea */
  #cursorCol(): number {
    return this.#cursor - this.#lineStart();
  }

  /** Largo de la línea actual */
  #currentLineLength(): number {
    return this.#lineEnd() - this.#lineStart();
  }

  /** Mueve el cursor al principio de la línea anterior */
  #moveToPrevLine(): void {
    const ls = this.#lineStart();
    if (ls === 0) return; // ya en primera línea
    const prevEnd = ls - 1; // el \n anterior
    const prevStart = this.#buffer.lastIndexOf("\n", prevEnd - 1);
    const prevLineStart = prevStart === -1 ? 0 : prevStart + 1;
    const prevLineLen = prevEnd - prevLineStart;
    const col = this.#cursor - ls; // columna actual
    this.#cursor = prevLineStart + Math.min(col, prevLineLen);
  }

  /** Mueve el cursor al principio de la línea siguiente */
  #moveToNextLine(): void {
    const le = this.#lineEnd();
    if (le === this.#buffer.length) return; // ya en última línea
    const nextStart = le + 1; // después del \n
    const nextEnd = this.#buffer.indexOf("\n", nextStart);
    const nextLineEnd = nextEnd === -1 ? this.#buffer.length : nextEnd;
    const nextLineLen = nextLineEnd - nextStart;
    const col = this.#cursor - this.#lineStart();
    this.#cursor = nextStart + Math.min(col, nextLineLen);
  }

  /** Busca inicio de palabra hacia atrás desde cursor */
  #prevWordBoundary(): number {
    let i = this.#cursor - 1;
    // saltar whitespace
    while (i >= 0 && this.#buffer[i] === " ") i--;
    // saltar no-whitespace
    while (i >= 0 && this.#buffer[i] !== " " && this.#buffer[i] !== "\n") i--;
    return i + 1;
  }

  // ---- handleKey ----

  handleKey(key: Key): void {
    switch (key.type) {
      case "char":
        this.#insertAtCursor(key.value);
        break;
      case "paste":
        this.#insertAtCursor(key.text);
        break;
      case "newline":
        this.#insertAtCursor("\n");
        break;
      case "backspace":
        this.#backspaceAtCursor();
        break;
      case "delete":
        this.#deleteAtCursor();
        break;
      case "enter":
        this.#commit();
        break;
      case "left":
        if (this.#cursor > 0) this.#cursor--;
        break;
      case "right":
        if (this.#cursor < this.#buffer.length) this.#cursor++;
        break;
      case "home":
        this.#cursor = this.#lineStart();
        break;
      case "end":
        this.#cursor = this.#lineEnd();
        break;
      case "up":
        this.#handleUp();
        break;
      case "down":
        this.#handleDown();
        break;
      case "ctrl":
        this.#handleCtrl(key.key);
        break;
      // escape, tab, unknown → ignorados
    }
  }

  isDone(): boolean {
    return this.#done;
  }

  getResult(): string {
    // devolvemos el buffer sin el \n final que se agrega en el commit
    return this.#buffer.endsWith("\n")
      ? this.#buffer.slice(0, -1)
      : this.#buffer;
  }

  render(): string {
    const W = this.#boxWidth();
    const bar = dim("─".repeat(W));
    const promptLen = this.#promptStr.length;
    const indent = " ".repeat(promptLen);

    const lines = this.#buffer.split("\n");
    const content = lines.map((l, i) => (i === 0 ? this.#promptStr : indent) + l);

    return [bar, ...content, bar].join("\n");
  }

  /** Render del mensaje enviado SIN la caja (barras), para ecoarlo en el
   * historial. Así el mensaje no se ve igual que el prompt de input de abajo. */
  renderEcho(): string {
    const indent = " ".repeat(this.#promptStr.length);
    return this.#buffer
      .split("\n")
      .map((l, i) => (i === 0 ? this.#promptStr : indent) + l)
      .join("\n");
  }

  getCursorPosition(): CursorPosition {
    const line = this.#cursorLine();
    const col = (line === 0 ? this.#promptStr.length : 2) + this.#cursorCol();
    return { row: line + 1, col };
  }

  /** Ancho de la barra horizontal: usa el ancho completo del terminal. */
  #boxWidth(): number {
    return stdout.columns || 80;
  }

  // ---- privados ----

  #insertAtCursor(text: string): void {
    this.#buffer =
      this.#buffer.slice(0, this.#cursor) +
      text +
      this.#buffer.slice(this.#cursor);
    this.#cursor += text.length;
  }

  #backspaceAtCursor(): void {
    if (this.#cursor === 0) return;
    this.#buffer =
      this.#buffer.slice(0, this.#cursor - 1) +
      this.#buffer.slice(this.#cursor);
    this.#cursor--;
  }

  #deleteAtCursor(): void {
    if (this.#cursor >= this.#buffer.length) return;
    this.#buffer =
      this.#buffer.slice(0, this.#cursor) +
      this.#buffer.slice(this.#cursor + 1);
  }

  #commit(): void {
    this.#done = true;
  }

  #handleUp(): void {
    const totalLines = this.#lineCount();
    const curLine = this.#cursorLine();

    // Si estamos en la primera línea y no hay multilínea, navegar historia
    if (curLine === 0 && totalLines === 1) {
      this.#navigateHistoryUp();
      return;
    }

    // Si estamos en la primera línea del buffer multilínea, navegar historia
    if (curLine === 0 && totalLines > 1) {
      this.#navigateHistoryUp();
      return;
    }

    // Si no, mover cursor a línea anterior
    this.#moveToPrevLine();
  }

  #handleDown(): void {
    const totalLines = this.#lineCount();
    const curLine = this.#cursorLine();

    // Si estamos navegando historia, bajamos en el historial o volvemos al draft
    if (this.#historyIndex >= 0) {
      this.#navigateHistoryDown();
      return;
    }

    // Si estamos en la última línea del buffer, navegar historia
    if (curLine === totalLines - 1) {
      this.#navigateHistoryDown();
      return;
    }

    // Si no, mover cursor a línea siguiente
    this.#moveToNextLine();
  }

  #navigateHistoryUp(): void {
    if (this.#history.length === 0) return;

    // Guardar buffer actual como draft la primera vez
    if (this.#historyIndex === -1) {
      this.#draftBuffer = this.#buffer;
      this.#draftCursor = this.#cursor;
      this.#historyIndex = this.#history.length - 1;
    } else if (this.#historyIndex > 0) {
      this.#historyIndex--;
    } else {
      return; // ya en el más viejo
    }

    this.#buffer = this.#history[this.#historyIndex];
    this.#cursor = this.#buffer.length;
  }

  #navigateHistoryDown(): void {
    if (this.#historyIndex === -1) return;

    if (this.#historyIndex < this.#history.length - 1) {
      this.#historyIndex++;
      this.#buffer = this.#history[this.#historyIndex];
      this.#cursor = this.#buffer.length;
    } else {
      // Volver al draft
      this.#historyIndex = -1;
      this.#buffer = this.#draftBuffer;
      this.#cursor = this.#draftCursor;
    }
  }

  #handleCtrl(key: string): void {
    switch (key) {
      case "a":
        this.#cursor = this.#lineStart();
        break;
      case "e":
        this.#cursor = this.#lineEnd();
        break;
      case "u":
        // borrar desde inicio de línea hasta cursor
        this.#deleteRange(this.#lineStart(), this.#cursor);
        break;
      case "k":
        // borrar desde cursor hasta fin de línea
        this.#deleteRange(this.#cursor, this.#lineEnd());
        break;
      case "w":
        this.#deleteRange(this.#prevWordBoundary(), this.#cursor);
        break;
      // ctrl+c se maneja en render.ts, así que acá no llega
    }
  }

  #deleteRange(from: number, to: number): void {
    if (from >= to) return;
    this.#buffer = this.#buffer.slice(0, from) + this.#buffer.slice(to);
    this.#cursor = from;
  }

  // ---- API pública para comandos ----

  /** Agrega un comando al historial (lo llama el driver tras cada commit) */
  addToHistory(cmd: string): void {
    // No duplicar consecutivos
    if (this.#history.length > 0 && this.#history[this.#history.length - 1] === cmd) {
      return;
    }
    this.#history.push(cmd);
  }
}

export { LineEditor };

