  process.on("exit", disableRawMode);

  // Restaurar ante SIGTERM. SIGINT se maneja en el Screen/runner para
  // interrumpir al agente sin matar el proceso.
  process.on("SIGTERM", () => {
    disableRawMode();
    process.exit(1);
  });

