async *callStream(
  messages: Message[],
  agent: AgentConfig,
  signal?: AbortSignal,
): AsyncGenerator<StreamEvent> {
  const headers: Record<string, string> = {
    Authorization: `Bearer ${this.apiKey()}`,
    "Content-Type": "application/json",
  };

  const body = {
    model: agent.model,
    messages: translateMessages(messages, agent.systemPrompt),
    tools: translateTools(agent),
    max_tokens: agent.maxTokens,
    stream: true,
  };

  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), TIMEOUT_MS * 2);

  // Si el usuario interrumpe (SIGINT), abortar el fetch
  const onAbort = () => controller.abort();
  signal?.addEventListener("abort", onAbort, { once: true });

  let response: Response;
  try {
    response = await fetch(this.url(), {
      method: "POST",
      headers,
      body: JSON.stringify(body),
      signal: controller.signal,
    });
  } catch (err: unknown) {
    clearTimeout(timeoutId);
    signal?.removeEventListener("abort", onAbort);
    if (err instanceof Error && err.name === "AbortError") {
      throw new Error(`Stream request timeout after ${TIMEOUT_MS * 2}ms`);
    }
    throw err;
  }
  clearTimeout(timeoutId);
  signal?.removeEventListener("abort", onAbort);

